// Advanced Display Filter Examples — Copy-Paste Ready

// Detect SYN port scanning
tcp.flags.syn == 1 && tcp.flags.ack == 0

// Find SQL injection attempts in HTTP URIs
http.request.uri matches "(UNION|SELECT|OR 1=1|DROP TABLE)"

// Detect DNS tunneling (long subdomains)
dns.qry.name matches "[a-z0-9]{25}\\."

// Find TLS Client Hello packets
tls.handshake.type == 1

// Isolate traffic between two specific hosts
(ip.src == 192.168.1.10 && ip.dst == 10.0.0.5) || (ip.src == 10.0.0.5 && ip.dst == 192.168.1.10)

// Detect ICMP tunneling by payload size
icmp && data.len > 100

// Find HTTP responses with error codes
http.response.code >= 400 && http.response.code <= 599

// Detect FTP brute force (login failure responses)
ftp.response.code == 530
